import{_ as o}from"./nyalra_kb-7135827b.js";import{_ as l,W as n,X as p,Y as c,Z as e,$ as a,a1 as i,a0 as r,C as d}from"./framework-91490e6a.js";const s={},g=e("figure",null,[e("img",{src:o,alt:"",tabindex:"0",loading:"lazy"}),e("figcaption")],-1),m={href:"https://tree-novel.com/works/episode/1d683e7a8ee0909e15ad93f7b948111c.html",target:"_blank",rel:"noopener noreferrer"},f=r('<blockquote><p>这是在互联网中栖息的不可思议生物·Nyalra于深夜写下的有关互联网、独居生活以及除此之外的事物的图文随笔。</p></blockquote><p>独自。</p><p>现在，我处在宽敞的房间之中，被大量的书籍与手办包围，忍受着每一夜的孤独。</p><p>要自我介绍一下吗。我以「にゃるら」这个出处明显的名字在十几岁时创建了Twitter账号。在当时也为了掩饰孤独而更新博客，通过写作来保持与人类社会的联系。随着时间的推移，渐渐地传来了工作委托。在积累了各种各样的经验之后，今年年初以总监督（策划和剧本）的身份发布了标题为「NEEDY GIRL OVERDOSE」的游戏。</p><figure><img src="https://img.tree-novel.com/talk/749e8a1baeadce03fffdb730bb714200.jpg" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>这款游戏值得庆幸地达到了几十万销量，因此幸运的我成功地租到了一个能够陈列我所喜爱的书籍和手办的房间。由于天花板高达3米有余，房间结构相当复杂，很难找到租客。这间房似乎在说「我很挑剔，普通人不行！」。然而，这反而激发了我的创造精神，让我充满了「我要把它打造成最棒的宅宅房间！」的决心。嘛，虽然也因为没有租客，和面积比起来，租金之类的也相对便宜了一些。</p><p><img src="https://img.tree-novel.com/talk/010d5b6be860ea8791c6b928b10018f1.png" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/65677d96659f367ad28adc4a61a762d4.png" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/fdc4eb918a271e5bc8841abae6632cc8.png" alt="" loading="lazy"></p><p>总而言之我非常喜欢书和手办。我视它们整齐陈列的空间为至上，尽量不放置家电，我想省出空间陈列书籍。我对饮食没有兴趣，所以从未做过饭。直到现在，连冰箱都没有。由于这种生活，有时别人来玩时甚至会担心「完全感受不到人类的生活气息……」。</p><p>在这样的房间之中深夜发呆，即使是一个按照自己的意愿创造出来的空间，也会产生孤寂感。在摆满了手办、游戏等令人欢快的物品的房间里，自己却孤独地独处。这种落差散发出一种类似于“边缘空间”的悲伤感。当然，就在这个毫无人情味的房间之中，我也在静静地打着这些文字。键盘的敲击声是唯一在昏暗的房间里回荡的声音。</p><figure><img src="https://img.tree-novel.com/talk/533671a6ed243ba027d56526dd0722d1.png" alt="" tabindex="0" loading="lazy"><figcaption></figcaption></figure><p>「人，在与他人在一起时才会真正感受到孤独。」是谁写的呢？我记得差不多是坂口安吾这样说的。现在的我，深有体会。</p><p>如今，只要打开互联网，每个人都能与不特定的大量的人连接在一起。正因如此，与他人连接得越多，感受到的孤独也就越强烈。深夜的timeline上，几乎没有人发布商业性的推文，只有各人「孤独」的思绪流淌。尽管看似大家都聚集在社交媒体上，但实际上每个人只是在向着墙壁倾诉自己的心声。这种寂寞感不错。人们逐渐明白自己本质上是孤独的。</p><p>我开始写这个系列，也是为了在某种程度上减轻这种孤独感。编辑找我合作时，我感到很高兴。你们愿意关注我，对我有兴趣，这让我感到温暖。通过开始这个系列，我至少能通过编辑与其他人连接，如果能在深夜减轻一些孤独，我认为这就足够了。我是一个容易感到孤独的人，无法改变。</p><p>阅读这篇文章的时候，你可能会是一个人。就连现在，作为读者的你也在默默地面对手机或者屏幕，为了消磨时间和孤独，也许正读着我这样的专栏。</p><p>即使只是一瞬间，如果我能稍稍减轻你的孤独，那么写下这篇长文就是值得的。尽管我们彼此都是孤独的，但还是让我们继续保持这种伪装的相连吧。</p><p><img src="https://img.tree-novel.com/talk/d05e4e53ac75da6adb90dd007644387e.png" alt="" loading="lazy"><img src="https://img.tree-novel.com/talk/de435b114f11adbac291b4dc75f363b3.JPG" alt="" loading="lazy"></p><blockquote><p>本周的にゃるら的物品：</p><p>【巨大的公仔·优梨華大人×3】 这是出现在《Aikatsu！偶像活动！》中的吸血鬼优梨華大人的巨大公仔。虽然因为太大占用了位置，但如果不能摆放优梨華大人的话，生活就失去了意义，所以这样也挺好的。</p></blockquote>',17);function b(_,k){const t=d("ExternalLinkIcon");return n(),p("div",null,[c(" more "),g,e("p",null,[a("原文链接："),e("a",m,[a("第1回／にゃるらです"),i(t)])]),f])}const v=l(s,[["render",b],["__file","nyalra_kb_01.html.vue"]]);export{v as default};
